  1	import type { FC } from 'react';
  2	import { useWatch } from 'react-hook-form';
  3	import { PROVIDER_TYPES } from 'src/providers/utils/constants';
  4	
  5	import ExpandableReviewSection from '@components/ExpandableReviewSection/ExpandableReviewSection';
  6	import {
  7	  DescriptionList,
  8	  DescriptionListDescription,
  9	  DescriptionListGroup,
 10	  DescriptionListTerm,
 11	  useWizardContext,
 12	} from '@patternfly/react-core';
 13	import { isEmpty } from '@utils/helpers';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	
 16	import { planStepNames, PlanWizardStepId } from '../../constants';
 17	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 18	import { hasLiveMigrationProviderType } from '../../utils/hasLiveMigrationProviderType';
 19	import { GeneralFormFieldId } from '../general-information/constants';
 20	import { MigrationTypeFieldId, MigrationTypeValue } from '../migration-type/constants';
 21	import { otherFormFieldLabels, OtherSettingsFormFieldId } from '../other-settings/constants';
 22	
 23	const OtherSettingsReviewSection: FC<{ isLiveMigrationFeatureEnabled: boolean }> = ({
 24	  isLiveMigrationFeatureEnabled,
 25	}) => {
 26	  const { t } = useForkliftTranslation();
 27	  const { goToStepById } = useWizardContext();
 28	  const { control } = useCreatePlanFormContext();
 29	  const [
 30	    sourceProvider,
 31	    diskPassPhrases,
 32	    nbdeClevis,
 33	    transferNetwork,
 34	    preserveStaticIps,
 35	    rootDevice,
 36	    sharedDisks,
 37	    targetPowerState,
 38	    migrationType,
 39	  ] = useWatch({
 40	    control,
 41	    name: [
 42	      GeneralFormFieldId.SourceProvider,
 43	      OtherSettingsFormFieldId.DiskDecryptionPassPhrases,
 44	      OtherSettingsFormFieldId.NBDEClevis,
 45	      OtherSettingsFormFieldId.TransferNetwork,
 46	      OtherSettingsFormFieldId.PreserveStaticIps,
 47	      OtherSettingsFormFieldId.RootDevice,
 48	      OtherSettingsFormFieldId.MigrateSharedDisks,
 49	      OtherSettingsFormFieldId.TargetPowerState,
 50	      MigrationTypeFieldId.MigrationType,
 51	    ],
 52	  });
 53	  const isVsphere = sourceProvider?.spec?.type === PROVIDER_TYPES.vsphere;
 54	  const hasNoDiskPassPhrases =
 55	    isEmpty(diskPassPhrases) || (diskPassPhrases.length === 1 && !diskPassPhrases[0].value);
 56	
 57	  const isTransferNetworkVisible =
 58	    !hasLiveMigrationProviderType(sourceProvider) ||
 59	    !isLiveMigrationFeatureEnabled ||
 60	    migrationType !== MigrationTypeValue.Live;
 61	
 62	  return (
 63	    <ExpandableReviewSection
 64	      title={planStepNames[PlanWizardStepId.OtherSettings]}
 65	      testId="review-other-settings-section"
 66	      onEditClick={() => {
 67	        goToStepById(PlanWizardStepId.OtherSettings);
 68	      }}
 69	    >
 70	      <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
 71	        {isVsphere && (
 72	          <>
 73	            <DescriptionListGroup>
 74	              <DescriptionListTerm>{t('Use NBDE/Clevis')}</DescriptionListTerm>
 75	
 76	              <DescriptionListDescription data-testid="review-nbde-clevis">
 77	                {nbdeClevis ? t('Enabled') : t('Disabled')}
 78	              </DescriptionListDescription>
 79	            </DescriptionListGroup>
 80	
 81	            {!nbdeClevis && (
 82	              <DescriptionListGroup>
 83	                <DescriptionListTerm>
 84	                  {otherFormFieldLabels[OtherSettingsFormFieldId.DiskDecryptionPassPhrases]}
 85	                </DescriptionListTerm>
 86	
 87	                {hasNoDiskPassPhrases ? (
 88	                  <DescriptionListDescription data-testid="review-disk-decryption-passphrases">
 89	                    {t('None')}
 90	                  </DescriptionListDescription>
 91	                ) : (
 92	                  diskPassPhrases.map((diskPassPhrase) => (
 93	                    <DescriptionListDescription
 94	                      key={diskPassPhrase.value}
 95	                      data-testid="review-disk-decryption-passphrases"
 96	                    >
 97	                      {diskPassPhrase.value}
 98	                    </DescriptionListDescription>
 99	                  ))
100	                )}
101	              </DescriptionListGroup>
102	            )}
103	          </>
104	        )}
105	
106	        {isTransferNetworkVisible && (
107	          <DescriptionListGroup>
108	            <DescriptionListTerm>
109	              {otherFormFieldLabels[OtherSettingsFormFieldId.TransferNetwork]}
110	            </DescriptionListTerm>
111	
112	            <DescriptionListDescription data-testid="review-transfer-network">
113	              {transferNetwork?.name ?? t('Target provider default')}
114	            </DescriptionListDescription>
115	          </DescriptionListGroup>
116	        )}
117	
118	        {isVsphere && (
119	          <>
120	            <DescriptionListGroup>
121	              <DescriptionListTerm>
122	                {otherFormFieldLabels[OtherSettingsFormFieldId.PreserveStaticIps]}
123	              </DescriptionListTerm>
124	
125	              <DescriptionListDescription data-testid="review-preserve-static-ips">
126	                {preserveStaticIps ? t('Enabled') : t('Disabled')}
127	              </DescriptionListDescription>
128	            </DescriptionListGroup>
129	
130	            <DescriptionListGroup>
131	              <DescriptionListTerm>
132	                {otherFormFieldLabels[OtherSettingsFormFieldId.RootDevice]}
133	              </DescriptionListTerm>
134	
135	              <DescriptionListDescription data-testid="review-root-device">
136	                {rootDevice ?? t('First root device')}
137	              </DescriptionListDescription>
138	            </DescriptionListGroup>
139	
140	            <DescriptionListGroup>
141	              <DescriptionListTerm>
142	                {otherFormFieldLabels[OtherSettingsFormFieldId.MigrateSharedDisks]}
143	              </DescriptionListTerm>
144	
145	              <DescriptionListDescription data-testid="review-shared-disks">
146	                {sharedDisks ? t('Enabled') : t('Disabled')}
147	              </DescriptionListDescription>
148	            </DescriptionListGroup>
149	          </>
150	        )}
151	
152	        <DescriptionListGroup>
153	          <DescriptionListTerm>
154	            {otherFormFieldLabels[OtherSettingsFormFieldId.TargetPowerState]}
155	          </DescriptionListTerm>
156	
157	          <DescriptionListDescription data-testid="review-target-power-state">
158	            {targetPowerState.label}
159	          </DescriptionListDescription>
160	        </DescriptionListGroup>
161	      </DescriptionList>
162	    </ExpandableReviewSection>
163	  );
164	};
165	
166	export default OtherSettingsReviewSection;

