  1	import { FormProvider, useForm } from 'react-hook-form';
  2	import { PROVIDER_TYPES } from 'src/providers/utils/constants';
  3	
  4	import { beforeEach, describe, expect, it } from '@jest/globals';
  5	import { render, screen } from '@testing-library/react';
  6	
  7	import { GeneralFormFieldId } from '../../general-information/constants';
  8	import { OtherSettingsFormFieldId } from '../../other-settings/constants';
  9	import OtherSettingsReviewSection from '../OtherSettingsReviewSection';
 10	
 11	const mockUseCreatePlanFormContext = jest.fn();
 12	jest.mock('../../../hooks/useCreatePlanFormContext', () => ({
 13	  useCreatePlanFormContext: () => mockUseCreatePlanFormContext(),
 14	}));
 15	
 16	const mockGoToStepById = jest.fn();
 17	jest.mock('@patternfly/react-core', () => ({
 18	  ...jest.requireActual('@patternfly/react-core'),
 19	  useWizardContext: () => ({ goToStepById: mockGoToStepById }),
 20	}));
 21	
 22	const TestWrapper = ({
 23	  sourceProvider,
 24	  nbdeClevis = false,
 25	  diskPassPhrases = [],
 26	}: {
 27	  sourceProvider: any;
 28	  nbdeClevis?: boolean;
 29	  diskPassPhrases?: any[];
 30	}) => {
 31	  const methods = useForm({
 32	    defaultValues: {
 33	      [GeneralFormFieldId.SourceProvider]: sourceProvider,
 34	      [OtherSettingsFormFieldId.NBDEClevis]: nbdeClevis,
 35	      [OtherSettingsFormFieldId.DiskDecryptionPassPhrases]: diskPassPhrases,
 36	      [OtherSettingsFormFieldId.TransferNetwork]: null,
 37	      [OtherSettingsFormFieldId.PreserveStaticIps]: true,
 38	      [OtherSettingsFormFieldId.RootDevice]: '',
 39	      [OtherSettingsFormFieldId.MigrateSharedDisks]: false,
 40	      [OtherSettingsFormFieldId.TargetPowerState]: { label: 'Running' },
 41	    },
 42	  });
 43	
 44	  mockUseCreatePlanFormContext.mockReturnValue({ control: methods.control });
 45	
 46	  return (
 47	    <FormProvider {...methods}>
 48	      <OtherSettingsReviewSection />
 49	    </FormProvider>
 50	  );
 51	};
 52	
 53	describe('OtherSettingsReviewSection', () => {
 54	  beforeEach(() => {
 55	    jest.clearAllMocks();
 56	  });
 57	
 58	  const vsphereProvider = { spec: { type: PROVIDER_TYPES.vsphere } };
 59	
 60	  it('shows abbreviated NBDE label', () => {
 61	    render(<TestWrapper sourceProvider={vsphereProvider} />);
 62	    expect(screen.getByText('Use NBDE/Clevis')).toBeInTheDocument();
 63	  });
 64	
 65	  it('shows Enabled/Disabled status for NBDE', () => {
 66	    render(<TestWrapper sourceProvider={vsphereProvider} nbdeClevis={false} />);
 67	    expect(screen.getByTestId('review-nbde-clevis')).toHaveTextContent('Disabled');
 68	  });
 69	
 70	  it('shows Enabled status when NBDE is true', () => {
 71	    render(<TestWrapper sourceProvider={vsphereProvider} nbdeClevis={true} />);
 72	    expect(screen.getByTestId('review-nbde-clevis')).toHaveTextContent('Enabled');
 73	  });
 74	
 75	  it('shows passphrases when NBDE is disabled', () => {
 76	    const diskPassPhrases = [{ value: 'test-pass' }];
 77	    render(<TestWrapper sourceProvider={vsphereProvider} diskPassPhrases={diskPassPhrases} />);
 78	
 79	    expect(screen.getByText('Disk decryption passphrases')).toBeInTheDocument();
 80	    expect(screen.getByText('test-pass')).toBeInTheDocument();
 81	  });
 82	
 83	  it('hides passphrases when NBDE is enabled', () => {
 84	    const diskPassPhrases = [{ value: 'test-pass' }];
 85	    render(
 86	      <TestWrapper
 87	        sourceProvider={vsphereProvider}
 88	        nbdeClevis={true}
 89	        diskPassPhrases={diskPassPhrases}
 90	      />,
 91	    );
 92	
 93	    expect(screen.queryByText('Disk decryption passphrases')).not.toBeInTheDocument();
 94	    expect(screen.queryByText('test-pass')).not.toBeInTheDocument();
 95	  });
 96	
 97	  it('shows "None" when no passphrases and NBDE disabled', () => {
 98	    render(<TestWrapper sourceProvider={vsphereProvider} diskPassPhrases={[]} />);
 99	
100	    expect(screen.getByTestId('review-disk-decryption-passphrases')).toHaveTextContent('None');
101	  });
102	
103	  it('hides NBDE fields for non-vSphere providers', () => {
104	    const nonVsphereProvider = { spec: { type: PROVIDER_TYPES.ovirt } };
105	    render(<TestWrapper sourceProvider={nonVsphereProvider} />);
106	
107	    expect(screen.queryByText('Use NBDE/Clevis')).not.toBeInTheDocument();
108	  });
109	});

